+    "name~=1.0",
+    "name===arbitrarystring",
+    "name==1.0-alpha",
+    "name<=1!3.0.0.rc2",
+    "name>2.2,<3",
+    "name (==1.0)",
+    "name(>2.2,<3)",
+    "name()", // Empty specifier in parens
+    "name ==2.8.*",
