+// ============================================================================
+// Invalid dependency specifiers - MUST fail to parse
+// ============================================================================
+
+const INVALID_DEPENDENCIES = [_][]const u8{
+    // Empty string
+    "",
+
+    // No name
+    "==0.0",
+
+    // Missing comma in extras
+    "name[bar baz]",
+
+    // Trailing comma in extras
+    "name[bar, baz,]",
+
+    // Unclosed bracket
+    "name[bar, baz >= 1.0",
+    "name[bar, baz",
+
+    // Unclosed paren
